      <rect x="470" y="52" width="210" height="28" rx="4" fill="rgba(52,211,153,.18)" stroke="#34d399"/>
      <text x="575" y="71" fill="#34d399" font-size="14" font-weight="700" text-anchor="middle">自己保管ウォレット</text>
      <text x="20" y="118" fill="#a1a1aa" font-size="14">資産の保管者</text>
      <text x="350" y="118" fill="#e4e4e7" font-size="14" text-anchor="middle">取引所が代わりに保管</text>
      <text x="575" y="118" fill="#e4e4e7" font-size="14" text-anchor="middle">ユーザー本人</text>
